import Navbar from '../shared/Navbar';
import Footer from '../shared/Footer';

export default function Pricing() {
  const plans = [
    { name: 'Hot Desk', tagline: 'For individuals & freelancers', price: 699, unit: '/day', highlight: false, features: ['Any seat access', 'High-speed Wi‑Fi', 'Tea/Coffee', 'Community access'] },
    { name: 'Dedicated Desk', tagline: 'For consistent daily work', price: 1099, unit: '/day', highlight: true, features: ['Personal desk', 'Locker access', '24x7 access', 'Phone booths'] },
    { name: 'Private Office', tagline: 'For teams that scale', price: 1999, unit: '/day', highlight: false, features: ['Private cabin', 'Meeting credits', 'Onsite reception', 'Custom branding'] }
  ];

  const addons = [
    { name: 'Meeting Rooms', price: 499, unit: '/hour', desc: 'Pay-as-you-go professional rooms with AV' },
    { name: 'Parking', price: 199, unit: '/day', desc: 'Reserved parking spot (limited availability)' },
    { name: 'Storage Lockers', price: 99, unit: '/day', desc: 'Secure personal storage lockers' }
  ];

  const compare = [
    { feature: 'Wi‑Fi', hot: true, desk: true, office: true },
    { feature: '24x7 access', hot: false, desk: true, office: true },
    { feature: 'Locker', hot: false, desk: true, office: true },
    { feature: 'Private cabin', hot: false, desk: false, office: true },
    { feature: 'Meeting credits', hot: false, desk: false, office: true },
    { feature: 'Phone booths', hot: false, desk: true, office: true },
  ];

  return (
    <div className="min-h-screen flex flex-col bg-white">
      <Navbar />
      <main className="flex-1">
        {/* Hero */}
        <section className="relative overflow-hidden">
          <div className="absolute inset-0 bg-gradient-to-b from-brand-50/60 via-white to-white" />
          <div className="relative w-full px-6 md:px-12 lg:px-16 pt-14 pb-10">
            <h1 className="text-4xl font-extrabold tracking-tight text-gray-900">Simple, transparent pricing</h1>
            <p className="mt-3 text-lg text-gray-600">Flexible options for individuals, startups, and enterprises.</p>
          </div>
        </section>

        {/* Plans */}
        <section className="w-full px-6 md:px-12 lg:px-16 pb-6">
          <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
            {plans.map((p) => (
              <div key={p.name} className={`p-6 rounded-2xl border ${p.highlight ? 'border-brand-200 bg-white shadow-xl shadow-brand-100/50' : 'border-gray-100 bg-white shadow-card'}`}>
                {p.highlight && (
                  <div className="mb-3 inline-flex items-center gap-2 px-3 py-1 rounded-full bg-brand-50 text-brand-700 text-xs font-semibold">Most Popular</div>
                )}
                <div className="text-sm text-gray-600">{p.tagline}</div>
                <div className="mt-1 text-xl font-bold text-gray-900">{p.name}</div>
                <div className="mt-2 text-3xl font-extrabold text-gray-900">₹{p.price}<span className="text-base text-gray-500">{p.unit}</span></div>
                <ul className="mt-4 space-y-2 text-sm text-gray-700">
                  {p.features.map((f) => (
                    <li key={f} className="flex items-start gap-2">
                      <svg className="w-4 h-4 text-green-600 mt-0.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M5 13l4 4L19 7" /></svg>
                      <span>{f}</span>
                    </li>
                  ))}
                </ul>
                <a href="/search" className={`mt-6 inline-flex items-center justify-center h-11 w-full rounded-lg font-semibold transition ${p.highlight ? 'bg-brand-600 text-white hover:bg-brand-700' : 'bg-gray-900 text-white hover:bg-black'}`}>Get started</a>
              </div>
            ))}
          </div>
        </section>

        {/* Add-ons */}
        <section className="w-full px-6 md:px-12 lg:px-16 py-8">
          <h2 className="text-2xl font-bold text-gray-900">Add‑ons</h2>
          <div className="mt-4 grid grid-cols-1 md:grid-cols-3 gap-6">
            {addons.map((a) => (
              <div key={a.name} className="p-5 rounded-2xl border border-gray-100 bg-white shadow-card">
                <div className="text-gray-900 font-semibold">{a.name}</div>
                <div className="mt-1 text-gray-600 text-sm">{a.desc}</div>
                <div className="mt-3 text-xl font-bold text-gray-900">₹{a.price}<span className="text-sm text-gray-500">{a.unit}</span></div>
              </div>
            ))}
          </div>
        </section>

        {/* Comparison */}
        <section className="max-w-7xl mx-auto px-6 py-8">
          <h2 className="text-2xl font-bold text-gray-900">Compare plans</h2>
          <div className="mt-4 overflow-x-auto rounded-2xl border border-gray-100 bg-white">
            <table className="min-w-full text-sm">
              <thead>
                <tr className="bg-gray-50 text-gray-700">
                  <th className="text-left px-4 py-3 font-semibold">Feature</th>
                  <th className="px-4 py-3 font-semibold">Hot Desk</th>
                  <th className="px-4 py-3 font-semibold">Dedicated Desk</th>
                  <th className="px-4 py-3 font-semibold">Private Office</th>
                </tr>
              </thead>
              <tbody className="text-gray-700">
                {compare.map((row) => (
                  <tr key={row.feature} className="border-t border-gray-100">
                    <td className="px-4 py-3 text-gray-900">{row.feature}</td>
                    {[row.hot, row.desk, row.office].map((v, i) => (
                      <td key={i} className="px-4 py-3 text-center">
                        {v ? (
                          <svg className="w-4 h-4 mx-auto text-green-600" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M5 13l4 4L19 7" /></svg>
                        ) : (
                          <svg className="w-4 h-4 mx-auto text-gray-300" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12" /></svg>
                        )}
                      </td>
                    ))}
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
          <div className="mt-3 text-xs text-gray-500">Prices are indicative and may vary by city and availability.</div>
        </section>

        {/* FAQ */}
        <section className="max-w-7xl mx-auto px-6 py-10">
          <h2 className="text-2xl font-bold text-gray-900">Frequently asked questions</h2>
          <div className="mt-4 grid grid-cols-1 md:grid-cols-2 gap-6">
            {[{
              q: 'Do prices vary by city?', a: 'Yes, prices can vary based on location, demand, and amenities. The list above reflects starting prices.'
            }, {
              q: 'Can I upgrade or switch plans?', a: 'Absolutely. You can switch plans anytime based on availability and billing adjustments.'
            }, {
              q: 'Are meeting rooms included?', a: 'Meeting rooms are offered as add‑ons with hourly pricing and credits on higher tiers.'
            }, {
              q: 'Do you support team billing?', a: 'Yes. We can consolidate invoices and support enterprise procurement workflows.'
            }].map((f) => (
              <div key={f.q} className="p-5 rounded-2xl border border-gray-100 bg-white shadow-card">
                <div className="font-semibold text-gray-900">{f.q}</div>
                <div className="mt-1 text-sm text-gray-600">{f.a}</div>
              </div>
            ))}
          </div>
        </section>

        {/* Enterprise CTA */}
        <section className="bg-gradient-to-r from-brand-600 to-brand-700">
          <div className="max-w-7xl mx-auto px-6 py-12 md:py-14 flex flex-col md:flex-row items-center justify-between gap-4">
            <div>
              <div className="text-white text-2xl font-bold">Need a full‑floor or custom build‑out?</div>
              <p className="text-white/90 mt-1">Talk to sales for enterprise pricing, security, and SLAs.</p>
            </div>
            <a href="/contact" className="inline-flex items-center justify-center h-11 px-6 rounded-lg bg-white text-brand-700 font-semibold hover:bg-gray-100">Talk to sales</a>
          </div>
        </section>
      </main>
      <Footer />
    </div>
  );
}
